import { UserButton, useUser } from "@clerk/clerk-react";
import { Sprout } from "lucide-react";
import { Link } from "react-router-dom";
import { useUserRole } from "@/hooks/useUserRole";
import { useEffect } from "react";
import { requestFirebaseToken, onMessageListener } from "@/lib/firebase";
import { toast } from "sonner";

const roleLabels: Record<string, string> = {
    farmer: "Farmer",
    equipment_owner: "Equipment Owner",
    hotel_restaurant_manager: "Hotel / Restaurant",
};

const rolePaths: Record<string, string> = {
    farmer: "/farmer-dashboard",
    equipment_owner: "/equipment-dashboard",
    hotel_restaurant_manager: "/hotel-dashboard",
};

type DashboardLayoutProps = {
    children: React.ReactNode;
    subtitle: string;
};

const DashboardLayout = ({ children, subtitle }: DashboardLayoutProps) => {
    const { user } = useUser();
    const { role } = useUserRole();

    useEffect(() => {
        if (user) {
            requestFirebaseToken();

            const watchMessages = async () => {
                try {
                    const payload: any = await onMessageListener();
                    if (payload?.notification) {
                        toast.info(payload.notification.title || "New Notification", {
                            description: payload.notification.body
                        });
                    }
                    // Continue watching after one message
                    watchMessages();
                } catch (err) {
                    console.log('Firebase message watch failed:', err);
                }
            };
            watchMessages();
        }
    }, [user]);

    return (
        <div className="min-h-screen bg-background">
            <nav className="border-b border-border bg-card">
                <div className="container mx-auto flex items-center justify-between h-16 px-4">
                    <Link to="/" className="flex items-center gap-2">
                        <Sprout className="h-7 w-7 text-primary" />
                        <span className="font-display text-xl font-bold text-foreground">
                            Foamer's Connect
                        </span>
                    </Link>
                    <div className="flex items-center gap-4">
                        <span className="text-xs font-medium text-muted-foreground bg-muted px-3 py-1 rounded-full hidden sm:inline">
                            {role ? roleLabels[role] || role : ""}
                        </span>
                        <span className="text-sm text-muted-foreground hidden sm:inline">
                            {user?.firstName || "User"}
                        </span>
                        <UserButton afterSignOutUrl="/" />
                    </div>
                </div>
            </nav>

            <main className="container mx-auto px-4 py-12">
                <h1 className="font-display text-3xl md:text-4xl font-bold text-foreground mb-2">
                    Welcome, {user?.firstName || "User"}
                </h1>
                <p className="text-muted-foreground mb-10">{subtitle}</p>
                {children}
            </main>
        </div>
    );
};

export default DashboardLayout;

import { useState } from "react";
import { MapContainer, TileLayer, Marker, useMapEvents } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import L from "leaflet";

// Fix for default marker icon in react-leaflet
delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
    iconRetinaUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png",
    iconUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png",
    shadowUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png",
});

const defaultCenter = {
    lat: 20.5937,
    lng: 78.9629,
};

interface LocationPickerProps {
    onLocationSelected: (lat: number, lng: number) => void;
    initialLocation?: { lat: number; lng: number };
}

function LocationMarker({ position, setPosition, onLocationSelected }: any) {
    useMapEvents({
        click(e) {
            setPosition(e.latlng);
            onLocationSelected(e.latlng.lat, e.latlng.lng);
        },
    });

    return position === null ? null : (
        <Marker position={position}></Marker>
    );
}

export function LocationPicker({ onLocationSelected, initialLocation }: LocationPickerProps) {
    const [markerPosition, setMarkerPosition] = useState<{ lat: number, lng: number } | null>(initialLocation || null);

    const center = initialLocation || defaultCenter;
    const zoom = initialLocation ? 12 : 5;

    return (
        <div className="w-full relative border border-border rounded-lg overflow-hidden h-[400px]">
            <MapContainer
                center={[center.lat, center.lng]}
                zoom={zoom}
                scrollWheelZoom={true}
                style={{ height: "100%", width: "100%" }}
            >
                <TileLayer
                    attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                    url="https://tile.openstreetmap.org/{z}/{x}/{y}.png"
                />
                <LocationMarker
                    position={markerPosition}
                    setPosition={setMarkerPosition}
                    onLocationSelected={onLocationSelected}
                />
            </MapContainer>
        </div>
    );
}

