        .from("supply_contracts")
        .select("*", { count: "exact", head: true })
        .eq("farmer_id", farmerId)
        .eq("status", "active");

    if (error) {
        console.error("Error counting active contracts:", error);
        return 0;
    }

    return count || 0;
}

/**
 * Weather Service — integrates with OpenWeatherMap API
 * to provide current weather, forecasts, and farming-relevant alerts.
 *
 * Requires env var: VITE_OPENWEATHER_API_KEY
 */

const API_BASE = "https://api.openweathermap.org/data/2.5";

function getApiKey(): string {
    return import.meta.env.VITE_OPENWEATHER_API_KEY || "";
}

export type CurrentWeather = {
    temperature: number;      // Celsius
    feels_like: number;
    humidity: number;          // %
    wind_speed: number;        // m/s
    description: string;
    icon: string;
    rain_mm: number | null;    // mm in last 1h
    location_name: string;
};

export type WeatherForecastItem = {
    datetime: string;          // ISO timestamp
    temperature: number;
    feels_like: number;
    humidity: number;
    wind_speed: number;
    description: string;
    icon: string;
    rain_probability: number;  // 0-1
    rain_mm: number | null;
};

export type FarmingAlert = {
    type: "rain" | "temperature" | "wind" | "frost" | "heatwave";
    severity: "info" | "warning" | "critical";
    message: string;
    value: number;
};

/**
 * Fetch current weather for given coordinates
 */
export async function fetchCurrentWeather(lat: number, lon: number): Promise<CurrentWeather> {
    const apiKey = getApiKey();
    if (!apiKey) {
        throw new Error("OpenWeatherMap API key not configured. Set VITE_OPENWEATHER_API_KEY in .env");
    }

    const response = await fetch(
        `${API_BASE}/weather?lat=${lat}&lon=${lon}&units=metric&appid=${apiKey}`
    );

    if (!response.ok) {
        throw new Error(`Weather API error: ${response.status} ${response.statusText}`);
    }

    const data = await response.json();

    return {
        temperature: Math.round(data.main.temp),
        feels_like: Math.round(data.main.feels_like),
        humidity: data.main.humidity,
        wind_speed: data.wind.speed,
        description: data.weather?.[0]?.description || "Unknown",
        icon: data.weather?.[0]?.icon || "01d",
        rain_mm: data.rain?.["1h"] || null,
        location_name: data.name || "Unknown",
    };
}

/**
 * Fetch 5-day/3-hour forecast for given coordinates
 */
export async function fetchWeatherForecast(
    lat: number,
    lon: number
): Promise<WeatherForecastItem[]> {
    const apiKey = getApiKey();
    if (!apiKey) {
        throw new Error("OpenWeatherMap API key not configured. Set VITE_OPENWEATHER_API_KEY in .env");
    }

    const response = await fetch(
        `${API_BASE}/forecast?lat=${lat}&lon=${lon}&units=metric&appid=${apiKey}`
    );

    if (!response.ok) {
        throw new Error(`Weather API error: ${response.status} ${response.statusText}`);
    }

    const data = await response.json();

    return (data.list || []).map((item: any) => ({
        datetime: item.dt_txt,
        temperature: Math.round(item.main.temp),
        feels_like: Math.round(item.main.feels_like),
        humidity: item.main.humidity,
        wind_speed: item.wind.speed,
        description: item.weather?.[0]?.description || "Unknown",
        icon: item.weather?.[0]?.icon || "01d",
        rain_probability: item.pop || 0,
        rain_mm: item.rain?.["3h"] || null,
    }));
}

/**
 * Analyze forecast data and generate farming-relevant alerts
 */
export function generateFarmingAlerts(
    forecast: WeatherForecastItem[]
): FarmingAlert[] {
    const alerts: FarmingAlert[] = [];
    const next24h = forecast.slice(0, 8); // 8 × 3-hour intervals = 24 hours

    // Check for heavy rain
    const heavyRain = next24h.filter((f) => (f.rain_mm || 0) > 10);
    if (heavyRain.length > 0) {
        const maxRain = Math.max(...heavyRain.map((f) => f.rain_mm || 0));
        alerts.push({
            type: "rain",
            severity: maxRain > 30 ? "critical" : "warning",
            message: `Heavy rainfall expected (up to ${maxRain.toFixed(1)}mm). Consider protecting crops and delaying irrigation.`,
            value: maxRain,
        });
    }

    // Check for high rain probability
    const highRainProb = next24h.filter((f) => f.rain_probability > 0.7);
    if (highRainProb.length >= 3 && heavyRain.length === 0) {
        alerts.push({
            type: "rain",
            severity: "info",
            message: "Sustained rain likely in the next 24 hours. Plan outdoor activities accordingly.",
            value: Math.max(...highRainProb.map((f) => f.rain_probability)) * 100,
        });
    }

    // Check for frost (below 2°C)
    const frostRisk = next24h.filter((f) => f.temperature <= 2);
    if (frostRisk.length > 0) {
        const minTemp = Math.min(...frostRisk.map((f) => f.temperature));
        alerts.push({
            type: "frost",
            severity: minTemp <= 0 ? "critical" : "warning",
            message: `Frost risk! Temperature expected to drop to ${minTemp}°C. Protect sensitive crops.`,
            value: minTemp,
        });
    }

    // Check for extreme heat (above 40°C)
    const heatRisk = next24h.filter((f) => f.temperature >= 40);
    if (heatRisk.length > 0) {
        const maxTemp = Math.max(...heatRisk.map((f) => f.temperature));
        alerts.push({
            type: "heatwave",
            severity: maxTemp >= 45 ? "critical" : "warning",
            message: `Extreme heat expected (up to ${maxTemp}°C). Ensure adequate irrigation and shade for crops.`,
            value: maxTemp,
        });
    }

    // Check for high wind
    const highWind = next24h.filter((f) => f.wind_speed > 15);
    if (highWind.length > 0) {
        const maxWind = Math.max(...highWind.map((f) => f.wind_speed));
        alerts.push({
            type: "wind",
            severity: maxWind > 25 ? "critical" : "warning",
            message: `Strong winds expected (up to ${maxWind.toFixed(1)} m/s). Secure equipment and protect tall crops.`,
            value: maxWind,
        });
    }

    // General high temperature warning
    const hotDays = next24h.filter((f) => f.temperature >= 35 && f.temperature < 40);
    if (hotDays.length >= 4 && heatRisk.length === 0) {
        alerts.push({
            type: "temperature",
            severity: "info",
            message: "High temperatures expected. Increase watering frequency for heat-sensitive crops.",
            value: Math.max(...hotDays.map((f) => f.temperature)),
        });
    }

    return alerts;
}

/**
 * Get the OpenWeatherMap icon URL
 */
export function getWeatherIconUrl(iconCode: string): string {
    return `https://openweathermap.org/img/wn/${iconCode}@2x.png`;
}

/**
 * Convert location name to coordinates using OpenWeatherMap Geocoding API
 */
export async function geocodeLocation(
    locationName: string
): Promise<{ lat: number; lon: number; name: string } | null> {
    const apiKey = getApiKey();
    if (!apiKey) return null;

    const response = await fetch(
        `https://api.openweathermap.org/geo/1.0/direct?q=${encodeURIComponent(
            locationName
        )}&limit=1&appid=${apiKey}`
    );

    if (!response.ok) return null;

    const data = await response.json();
    if (!data || data.length === 0) return null;

    return {
        lat: data[0].lat,
        lon: data[0].lon,
        name: data[0].name,
    };
}

import { supabase } from "@/integrations/supabase/client";

export type UserProfile = {
  id: string;
  clerk_user_id: string;
  full_name: string | null;
  email: string | null;
  phone: string | null;
  location: string | null;
  // Role-specific fields joined via underlying tables:
  land_size_acres: number | null;
  soil_type: string | null;
  farming_type: string | null;
  available_equipment: string | null;
  avatar_url: string | null;
  created_at: string;
  updated_at: string;
};

export type UserRole = "farmer" | "equipment_owner" | "hotel_restaurant_manager";

/**
 * Test if Supabase is reachable. Returns true if connected, false otherwise.
 */
export async function testSupabaseConnection(): Promise<boolean> {
  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000); // 5s timeout

    const { error } = await supabase
      .from("profiles")
      .select("id", { count: "exact", head: true })
      .abortSignal(controller.signal);

    clearTimeout(timeout);
    return !error;
  } catch {
    return false;
  }
}

export async function syncClerkUserToSupabase(clerkUserId: string, userData: {
  full_name?: string;
  email?: string;
  avatar_url?: string;
}) {
  const { data: existing, error: fetchError } = await supabase
    .from("profiles")
    .select("id")
    .eq("clerk_user_id", clerkUserId)
    .maybeSingle();

  if (fetchError) {
    console.error("Error checking existing profile:", fetchError);
    throw new Error(
      `Cannot connect to database. Please check your Supabase URL and API key in the .env file. Details: ${fetchError.message}`
    );
  }

  if (existing) {
    const { data, error } = await supabase
      .from("profiles")
      .update({
        full_name: userData.full_name || null,
        email: userData.email || null,
        avatar_url: userData.avatar_url || null,
        updated_at: new Date().toISOString(),
      })
      .eq("clerk_user_id", clerkUserId)
      .select()
      .maybeSingle();

    if (error) throw new Error(`Failed to update profile: ${error.message}`);
    return data;
  } else {
    const { data, error } = await supabase
      .from("profiles")
      .insert({
        clerk_user_id: clerkUserId,
        full_name: userData.full_name || null,
        email: userData.email || null,
        avatar_url: userData.avatar_url || null,
      })
      .select()
      .single();

    if (error) throw new Error(`Failed to create profile: ${error.message}`);
    return data;
  }
}

export async function setUserRole(clerkUserId: string, role: UserRole) {
  const { data: existing } = await supabase
    .from("user_roles")
    .select("id")
    .eq("clerk_user_id", clerkUserId)
    .maybeSingle();

  const currentProfileId = await getProfileId(clerkUserId);

  if (existing) {
    const { data, error } = await supabase
      .from("user_roles")
      .update({ role: role as any })
      .eq("clerk_user_id", clerkUserId)
      .select()
      .maybeSingle();

    if (error) throw new Error(`Failed to update role: ${error.message}`);

    // Auto-create the relevant role profile linked table mapping
    if (currentProfileId) {
      if (role === 'farmer') {
        await (supabase as any).from("farmer_profiles").upsert({ profile_id: currentProfileId }, { onConflict: "profile_id" });
      } else if (role === 'equipment_owner') {
        await (supabase as any).from("equipment_owner_profiles").upsert({ profile_id: currentProfileId }, { onConflict: "profile_id" });
      } else if (role === 'hotel_restaurant_manager') {
        await (supabase as any).from("buyer_profiles").upsert({ profile_id: currentProfileId }, { onConflict: "profile_id" });
      }
    }

    return data;
  } else {
    const { data, error } = await supabase
      .from("user_roles")
      .insert({ clerk_user_id: clerkUserId, role: role as any })
      .select()
      .single();

    if (error) throw new Error(`Failed to set role: ${error.message}`);

    // Auto-create the relevant role profile linked table mapping
    if (currentProfileId) {
      if (role === 'farmer') {
        await (supabase as any).from("farmer_profiles").upsert({ profile_id: currentProfileId }, { onConflict: "profile_id" });
      } else if (role === 'equipment_owner') {
        await (supabase as any).from("equipment_owner_profiles").upsert({ profile_id: currentProfileId }, { onConflict: "profile_id" });
      } else if (role === 'hotel_restaurant_manager') {
        await (supabase as any).from("buyer_profiles").upsert({ profile_id: currentProfileId }, { onConflict: "profile_id" });
      }
    }

    return data;
  }
}

export async function getUserRole(clerkUserId: string): Promise<UserRole | null> {
  const { data, error } = await supabase
    .from("user_roles")
    .select("role")
    .eq("clerk_user_id", clerkUserId)
    .maybeSingle();

  if (error) return null;
  return data?.role as UserRole | null;
}

export async function getUserProfile(clerkUserId: string): Promise<UserProfile | null> {
  // We perform a left join to fetch the base profile + potential role profiles
  const { data, error } = await (supabase as any)
    .from("profiles")
    .select(`
      *,
      farmer_profiles(land_size_acres, soil_type, farming_type, available_equipment),
      equipment_owner_profiles(available_equipment)
    `)
    .eq("clerk_user_id", clerkUserId)
    .maybeSingle();

  if (error || !data) {
    console.error("Error getting user profile:", error);
    return null;
  }

  // Flatten the joined data into the single flat UserProfile interface expected by exactly the frontend
  const farmerData = data.farmer_profiles && Array.isArray(data.farmer_profiles) ? data.farmer_profiles[0] : (data.farmer_profiles || {});
  const equipmentOwnerData = data.equipment_owner_profiles && Array.isArray(data.equipment_owner_profiles) ? data.equipment_owner_profiles[0] : (data.equipment_owner_profiles || {});

  return {
    id: data.id,
    clerk_user_id: data.clerk_user_id,
    full_name: data.full_name,
    email: data.email,
    avatar_url: data.avatar_url,
    phone: data.phone,
    location: data.location,
    created_at: data.created_at,
    updated_at: data.updated_at,
    // Inherited role fields
    land_size_acres: farmerData?.land_size_acres || null,
    soil_type: farmerData?.soil_type || null,
    farming_type: farmerData?.farming_type || null,
    available_equipment: farmerData?.available_equipment || equipmentOwnerData?.available_equipment || null,
  };
}

export async function getProfileId(clerkUserId: string): Promise<string | null> {
  const { data, error } = await supabase
    .from("profiles")
    .select("id")
    .eq("clerk_user_id", clerkUserId)
    .maybeSingle();

  if (error) return null;
  return data?.id || null;
}

export async function updateUserProfile(
  clerkUserId: string,
  updates: Partial<UserProfile>
) {
  // 1. Update the base 'profiles' table
  const baseUpdates = {
    full_name: updates.full_name,
    phone: updates.phone,
    location: updates.location,
    updated_at: new Date().toISOString(),
  };

  const { data: baseData, error: baseError } = await supabase
    .from("profiles")
    .update(baseUpdates)
    .eq("clerk_user_id", clerkUserId)
    .select()
    .maybeSingle();

  if (baseError || !baseData) {
    throw baseError || new Error("Profile not found");
  }

  const profileId = baseData.id;
  const role = await getUserRole(clerkUserId);

  // 2. Upsert to the correct role-based table based on the fields sent
  if (role === "farmer") {
    const farmerUpdates: any = {
      profile_id: profileId,
      land_size_acres: updates.land_size_acres !== undefined ? updates.land_size_acres : null,
      soil_type: updates.soil_type !== undefined ? updates.soil_type : null,
      farming_type: updates.farming_type !== undefined ? updates.farming_type : null,
      available_equipment: updates.available_equipment !== undefined ? updates.available_equipment : null,
      updated_at: new Date().toISOString(),
    };
    await (supabase as any).from("farmer_profiles").upsert(farmerUpdates, { onConflict: "profile_id" });
  } else if (role === "equipment_owner") {
    const equipmentOwnerUpdates: any = {
      profile_id: profileId,
      available_equipment: updates.available_equipment !== undefined ? updates.available_equipment : null,
      updated_at: new Date().toISOString(),
    };
    await (supabase as any).from("equipment_owner_profiles").upsert(equipmentOwnerUpdates, { onConflict: "profile_id" });
  }

  // Frontend relies on the returned flat data representing the complete updated state.
  return await getUserProfile(clerkUserId);
}

import { useUser } from "@clerk/clerk-react";
import { useState, useEffect } from "react";
import { getUserProfile, updateUserProfile, getUserRole, UserProfile, UserRole } from "@/lib/supabase-auth";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import DashboardLayout from "@/components/DashboardLayout";
import { Loader2, Save } from "lucide-react";

const ProfilePage = () => {
    const { user } = useUser();
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [role, setRole] = useState<UserRole | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);

    const [fullName, setFullName] = useState("");
    const [email, setEmail] = useState("");
    const [phone, setPhone] = useState("");
    const [landSize, setLandSize] = useState("");
    const [soilType, setSoilType] = useState("");
    const [farmingType, setFarmingType] = useState("");
    const [locationName, setLocationName] = useState("");
    const [availableEquipment, setAvailableEquipment] = useState("");

    useEffect(() => {
        async function load() {
            if (!user?.id) return;
            setIsLoading(true);

            // Fetch profile and role in parallel
            const [profileData, userRole] = await Promise.all([
                getUserProfile(user.id),
                getUserRole(user.id)
            ]);

            setRole(userRole);

            if (profileData) {
                setProfile(profileData);
                setFullName(profileData.full_name || user.fullName || "");
                setEmail(profileData.email || user.primaryEmailAddress?.emailAddress || "");
                setPhone(profileData.phone || "");
                setLandSize(profileData.land_size_acres ? String(profileData.land_size_acres) : "");
                setSoilType(profileData.soil_type || "");
                setFarmingType(profileData.farming_type || "");
                setLocationName(profileData.location || "");
                setAvailableEquipment(profileData.available_equipment || "");
            }
            setIsLoading(false);
        }
        load();
    }, [user?.id]);

    const handleSave = async () => {
        if (!user?.id) return;
        setIsSaving(true);
        try {
            await updateUserProfile(user.id, {
                full_name: fullName || null,
                phone: phone || null,
                // Only save farmer-specific fields if they are a farmer. Otherwise null out.
                land_size_acres: role === "farmer" && landSize ? parseFloat(landSize) : null,
                soil_type: role === "farmer" ? (soilType || null) : null,
                farming_type: role === "farmer" ? (farmingType || null) : null,
                // Save available equipment for farmer and equipment owners. Otherwise null out.
                available_equipment: (role === "farmer" || role === "equipment_owner") ? (availableEquipment || null) : null,
                // Location is now strictly a string name for all roles
                location: locationName || null,
            });
            toast.success("Profile saved successfully!");
        } catch {
            toast.error("Failed to save profile");
        } finally {
            setIsSaving(false);
        }
    };

    if (isLoading) {
        return (
            <DashboardLayout subtitle="Manage your profile">
                <div className="flex justify-center py-20">
                    <Loader2 className="h-10 w-10 animate-spin text-primary" />
                </div>
            </DashboardLayout>
        );
    }

    return (
        <DashboardLayout subtitle="Manage your personal information and location.">
            <div className="max-w-3xl mx-auto space-y-8">
                {/* Personal Info - Appears for all roles */}
                <section className="bg-card rounded-xl border border-border p-6 space-y-4">
                    <h2 className="font-display text-xl font-semibold">Personal Information</h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="fullName">Full Name</Label>
                            <Input id="fullName" value={fullName} onChange={e => setFullName(e.target.value)} />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="email">Email</Label>
                            <Input id="email" value={email} disabled className="opacity-60" />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="phone">Phone</Label>
                            <Input id="phone" value={phone} onChange={e => setPhone(e.target.value)} placeholder="+91..." />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="locationName">Location (City/Village)</Label>
                            <Input id="locationName" value={locationName} onChange={e => setLocationName(e.target.value)} placeholder="e.g. Pune, Maharashtra" />
                        </div>
                    </div>
                </section>

                {/* Farm Details - ONLY for Farmers */}
                {role === "farmer" && (
                    <section className="bg-card rounded-xl border border-border p-6 space-y-4">
                        <h2 className="font-display text-xl font-semibold">Farm Details</h2>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label htmlFor="landSize">Land Size (Acres)</Label>
                                <Input id="landSize" type="number" value={landSize} onChange={e => setLandSize(e.target.value)} placeholder="e.g. 5" />
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="soilType">Soil Type</Label>
                                <Select value={soilType} onValueChange={setSoilType}>
                                    <SelectTrigger><SelectValue placeholder="Select soil type" /></SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="loamy">Loamy</SelectItem>
                                        <SelectItem value="clay">Clay</SelectItem>
                                        <SelectItem value="sandy">Sandy</SelectItem>
                                        <SelectItem value="black">Black Soil</SelectItem>
                                        <SelectItem value="red">Red Soil</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="farmingType">Farming Type</Label>
                                <Select value={farmingType} onValueChange={setFarmingType}>
                                    <SelectTrigger><SelectValue placeholder="Select type" /></SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="organic">Organic</SelectItem>
                                        <SelectItem value="conventional">Conventional</SelectItem>
                                        <SelectItem value="hydroponic">Hydroponic</SelectItem>
                                        <SelectItem value="greenhouse">Greenhouse</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="equipment">Available Equipment</Label>
                                <Input id="equipment" value={availableEquipment} onChange={e => setAvailableEquipment(e.target.value)} placeholder="e.g. Tractor, Plough" />
                            </div>
                        </div>
                    </section>
                )}

                {/* Equipment Details - ONLY for Equipment Owners */}
                {role === "equipment_owner" && (
                    <section className="bg-card rounded-xl border border-border p-6 space-y-4">
                        <h2 className="font-display text-xl font-semibold">Business Details</h2>
                        <div className="grid grid-cols-1 gap-4">
                            <div className="space-y-2">
                                <Label htmlFor="equipment">General Available Equipment Description</Label>
                                <Input id="equipment" value={availableEquipment} onChange={e => setAvailableEquipment(e.target.value)} placeholder="e.g. Fleet of 5 Tractors" />
                                <p className="text-xs text-muted-foreground mt-1">Use the 'My Equipment' dashboard page to list individual items for rent.</p>
                            </div>
                        </div>
                    </section>
                )}

                {/* Save */}
                <div className="flex justify-end pt-4">
                    <Button size="lg" onClick={handleSave} disabled={isSaving}>
                        {isSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
                        Save Profile
                    </Button>
                </div>
            </div>
        </DashboardLayout>
    );
};

export default ProfilePage;

